+    where
+        K: std::borrow::Borrow<Q>,
+        Q: std::hash::Hash + Eq + ?Sized,
+    {
+        match self.index.get(key) {
+            Some(Node::Small { value, .. } | Node::Main { value, .. }) => Some(value),
+            _ => None,
+        }
+    }
